- phương thức: tính tổng lương các nhân viên, nhập danh sách nhân viên từ bàn phím

answer:
class DSNV {
    ArrayList<NV> lstNV;
    void nhapDSNV() {
        int n, i;
        Scanner sc = new Scanner(System.in);
        System.out.print("Nhap so NV:");
        n = sc.nextInt();
        lstNV = new ArrayList(n);
        for (i = 0; i < n; i++) {
            NV x = new NV();
            x.nhap();
            lstNV.add(x);
        }
    }
    void tinhTongLuong() {
        float s = 0;
        for (NV x : lstNV)
            s = s + x.tinhluong();
    }
}

